import{_ as d,H as e,f as o,i as a}from"./chunks/framework.BHvCMIhP.js";const m=JSON.parse('{"title":"Rust 学习路线总览","description":"","frontmatter":{},"headers":[],"relativePath":"../rustLearning/01-Rust学习路线总览.md","filePath":"../rustLearning/01-Rust学习路线总览.md","lastUpdated":1778496697000}'),r={name:"../rustLearning/01-Rust学习路线总览.md"};function l(i,t,c,s,u,n){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="rust-学习路线总览" tabindex="-1">Rust 学习路线总览 <a class="header-anchor" href="#rust-学习路线总览" aria-label="Permalink to &quot;Rust 学习路线总览&quot;">​</a></h1><p>这是一份为<strong>已经有其他语言（如 JS/TS、Go、Java、C++）基础的开发者</strong>准备的 Rust 学习路线图。 从 &quot;Hello World&quot; 到 &quot;为什么我的生命周期编译不过&quot;，再到 &quot;用 Tokio 和 Axum 写高并发服务&quot; 的完整闭环。</p><blockquote><p>一句话先记住：Rust 不是为了折磨你而设计出所有权和生命周期的，它是为了在<strong>不使用垃圾回收（GC）<strong>的前提下，保证</strong>内存安全</strong>和<strong>无数据竞争的并发</strong>。</p></blockquote><hr><h2 id="一、整套教程的结构" tabindex="-1">一、整套教程的结构 <a class="header-anchor" href="#一、整套教程的结构" aria-label="Permalink to &quot;一、整套教程的结构&quot;">​</a></h2><p>按 &quot;从基础到系统编程&quot; 分五部分，<strong>前三部分讲语言特性，后两部分讲工程应用</strong>：</p><table tabindex="0"><thead><tr><th>部分</th><th>主题</th><th>解决的核心问题</th></tr></thead><tbody><tr><td>一、基础与所有权</td><td>语法、所有权、借用</td><td>Rust 最难也是最核心的心智模型建立</td></tr><tr><td>二、类型与抽象</td><td>Enum、Trait、泛型</td><td>如何在 Rust 中优雅地组织代码和复用逻辑</td></tr><tr><td>三、并发与异步</td><td>线程、Channel、Async/Await</td><td>突破单核，理解 Rust 的无畏并发与 Tokio 运行时</td></tr><tr><td>四、工程实战与生态</td><td>CLI、Web 服务、数据库</td><td>怎么用 Rust 把实际的活干了（Axum/SQLx）</td></tr><tr><td>五、进阶与系统级</td><td>宏、Unsafe、FFI、WASM</td><td>榨干性能，与底层系统和其他语言交互</td></tr></tbody></table><hr><h2 id="二、完整目录-规划约-30-篇" tabindex="-1">二、完整目录（规划约 30 篇） <a class="header-anchor" href="#二、完整目录-规划约-30-篇" aria-label="Permalink to &quot;二、完整目录（规划约 30 篇）&quot;">​</a></h2><h3 id="第一部分-基础语法与核心心智-所有权与借用" tabindex="-1">第一部分：基础语法与核心心智（所有权与借用） <a class="header-anchor" href="#第一部分-基础语法与核心心智-所有权与借用" aria-label="Permalink to &quot;第一部分：基础语法与核心心智（所有权与借用）&quot;">​</a></h3><ul><li><code>02-环境搭建与Cargo全家桶.md</code> —— 不只是编译器，更是无敌的包管理器</li><li><code>03-基础语法速通.md</code> —— 变量、数据类型、控制流（和其他语言大同小异）</li><li><code>04-所有权机制-Rust的灵魂.md</code> —— 为什么字符串赋值会报错（Move 语义）</li><li><code>05-引用与借用.md</code> —— 借东西要还，而且不能同时有人在改（读写锁原则）</li><li><code>06-切片（Slice）.md</code> —— 零拷贝访问集合序列</li><li><code>07-结构体与方法（Struct &amp; impl）.md</code> —— 面向对象的数据封装</li></ul><h3 id="第二部分-类型系统与抽象机制" tabindex="-1">第二部分：类型系统与抽象机制 <a class="header-anchor" href="#第二部分-类型系统与抽象机制" aria-label="Permalink to &quot;第二部分：类型系统与抽象机制&quot;">​</a></h3><ul><li><code>08-枚举与模式匹配（Enum &amp; Match）.md</code> —— 吊打其他语言的强大类型和分支</li><li><code>09-Option与Result-告别空指针与异常.md</code> —— 优雅的错误处理机制</li><li><code>10-集合类型.md</code> —— Vector、String 与 HashMap 的底层细节</li><li><code>11-泛型（Generics）.md</code> —— 消除重复代码</li><li><code>12-Trait-接口与多态.md</code> —— 鸭子类型与静态分发/动态分发（Box&lt;dyn Trait&gt;）</li><li><code>13-生命周期（Lifetimes）.md</code> —— 告诉编译器引用的有效范围（最折磨人的一集）</li></ul><h3 id="第三部分-闭包、并发与异步" tabindex="-1">第三部分：闭包、并发与异步 <a class="header-anchor" href="#第三部分-闭包、并发与异步" aria-label="Permalink to &quot;第三部分：闭包、并发与异步&quot;">​</a></h3><ul><li><code>14-闭包与迭代器.md</code> —— 函数式编程与零成本抽象</li><li><code>15-智能指针.md</code> —— Box、Rc、Arc、RefCell（绕过借用检查器的后门）</li><li><code>16-无畏并发-多线程与锁.md</code> —— Thread、Mutex、RwLock 与 Send/Sync</li><li><code>17-消息传递-Channel.md</code> —— 不要通过共享内存来通信，要通过通信来共享内存</li><li><code>18-Async与Await底层原理.md</code> —— Future、Waker 与 Pin 是什么鬼</li><li><code>19-Tokio运行时详解.md</code> —— Rust 异步生态的事实标准</li></ul><h3 id="第四部分-工程实战与生态-用-rust-干活" tabindex="-1">第四部分：工程实战与生态（用 Rust 干活） <a class="header-anchor" href="#第四部分-工程实战与生态-用-rust-干活" aria-label="Permalink to &quot;第四部分：工程实战与生态（用 Rust 干活）&quot;">​</a></h3><ul><li><code>20-编写命令行工具（CLI）.md</code> —— Clap、Anyhow 打造顺手的开发工具</li><li><code>21-Axum-现代Web框架入门.md</code> —— 路由、中间件与状态共享</li><li><code>22-数据库交互-SQLx与SeaORM.md</code> —— 异步查询与编译期 SQL 检查</li><li><code>23-Serde-序列化与反序列化.md</code> —— 统治整个生态的数据转换库</li><li><code>24-自动化测试与CI/CD.md</code> —— 单元测试、集成测试与 GitHub Actions</li><li><code>25-实战：写一个带 Auth 的 RESTful API.md</code> —— 把 Web 生态串起来</li></ul><h3 id="第五部分-底层深入与跨界" tabindex="-1">第五部分：底层深入与跨界 <a class="header-anchor" href="#第五部分-底层深入与跨界" aria-label="Permalink to &quot;第五部分：底层深入与跨界&quot;">​</a></h3><ul><li><code>26-Unsafe Rust.md</code> —— 我比编译器聪明，出了事我负责（裸指针与未定义行为）</li><li><code>27-宏（Macros）.md</code> —— 声明宏与过程宏（写代码的代码）</li><li><code>28-FFI-与其他语言交互.md</code> —— 把 Rust 编译成动态链接库给 C/Python/Node.js 用</li><li><code>29-WebAssembly（WASM）实战.md</code> —— 让 Rust 跑在浏览器里</li><li><code>30-Rust性能优化与火焰图.md</code> —— 找出代码中的性能瓶颈</li></ul><hr><h2 id="三、推荐的工具链" tabindex="-1">三、推荐的工具链 <a class="header-anchor" href="#三、推荐的工具链" aria-label="Permalink to &quot;三、推荐的工具链&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用途</th><th>工具</th><th>备注</th></tr></thead><tbody><tr><td>IDE/编辑器</td><td>RustRover (JetBrains) / VSCode (rust-analyzer) / Cursor</td><td><code>rust-analyzer</code> 是必备插件</td></tr><tr><td>编译器套件</td><td>rustup, rustc, cargo</td><td><code>rustup</code> 是安装管理器，<code>cargo</code> 是包管理器</td></tr><tr><td>格式化与Lint</td><td>rustfmt, clippy</td><td>每天提交代码前必跑 <code>cargo clippy</code></td></tr><tr><td>工具链切换</td><td><code>rustup default stable/nightly</code></td><td>某些前沿库可能需要 nightly 版本</td></tr></tbody></table><hr><h2 id="四、给新手的几个忠告" tabindex="-1">四、给新手的几个忠告 <a class="header-anchor" href="#四、给新手的几个忠告" aria-label="Permalink to &quot;四、给新手的几个忠告&quot;">​</a></h2><ol><li><strong>跟编译器做朋友，不要对抗它。</strong> Rust 编译器（rustc）的报错是世界上最友好的报错。仔细读它的提示，通常它已经把怎么改的代码都写在终端里了。</li><li><strong>第一周你会极度挫败。</strong> 写链表、图等数据结构时会被生命周期按在地上摩擦，这是正常的。先用 <code>.clone()</code> 把代码跑通，后期再来优化性能，不要一开始就追求零拷贝。</li><li><strong>不要一上来就写 Async。</strong> 在你彻底弄懂所有权、生命周期和 Trait 之前，强行写带引用的异步代码会让你陷入 <code>Pin</code> 和 <code>Lifetime</code> 的深渊。</li><li><strong>多用模式匹配和迭代器。</strong> 这是 Rust 写起来最爽的地方，习惯了之后你会觉得其他语言的 <code>if-else</code> 和 <code>for</code> 循环索然无味。</li></ol><hr><p>下一篇：<code>02-环境搭建与Cargo全家桶.md</code>，先把开发环境搞定。</p>',27)])])}const b=d(r,[["render",l]]);export{m as __pageData,b as default};
